fn factorial(n: i32) -> Result<u128, String> {
    if n < 0 {
        return Err("El número debe ser no negativo".to_string());
    }

    match n {
        0 => Ok(1),
        _ => factorial(n - 1).map(|res| res * n as u128),
    }
}

fn main() {
    // Caso positivo
    match factorial(5) {
        Ok(val) => println!("El factorial de 5 es: {}", val),
        Err(e) => println!("Error: {}", e),
    }

    // Caso cero
    match factorial(0) {
        Ok(val) => println!("El factorial de 0 es: {}", val),
        Err(e) => println!("Error: {}", e),
    }

    // Caso negativo
    match factorial(-1) {
        Ok(val) => println!("El factorial de -1 es: {}", val),
        Err(e) => println!("Error: {}", e),
    }
}
