/**
 * Realiza una solicitud GET con reintentos automáticos.
 * @param {string} url - La URL del endpoint.
 * @param {object} options - Opciones adicionales para fetch.
 * @param {number} maxRetries - Número máximo de intentos (por defecto 3).
 * @returns {Promise<any>} - Promesa con la respuesta JSON o lanza un error tras agotar reintentos.
 */
const fetchWithRetry = async (url, options = {}, maxRetries = 3) => {
  let lastError;

  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const response = await fetch(url, {
        ...options,
        method: 'GET',
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      lastError = error;
      console.warn(`Intento ${attempt}/${maxRetries} fallido: ${error.message}`);

      // Si no es el último intento, esperar antes de reintentar (backoff exponencial simple)
      if (attempt < maxRetries) {
        const delay = Math.pow(2, attempt) * 500; // 1s, 2s...
        await new Promise((resolve) => setTimeout(resolve, delay));
      }
    }
  }

  throw new Error(`Se agotaron los reintentos. Último error: ${lastError.message}`);
};

// Ejemplo de uso:
const API_URL = 'https://jsonplaceholder.typicode.com/posts/1';

fetchWithRetry(API_URL)
  .then((data) => console.log('Datos recibidos:', data))
  .catch((err) => console.error('Error final:', err.message));
